-- Migration Script: Add AreaID and Side to Serialization Array Tables
-- Purpose: Support multiple serialization orders per part based on area and side
-- Date: [MIGRATION_DATE]

USE [MES]
GO

-- Step 1: Add columns to Part_Operation_Serialization_Array_Size
