    ADD [AreaID] INT NOT NULL CONSTRAINT DF_POSARRAY_SIZE_AreaID DEFAULT (0);

    PRINT 'Added AreaID to Part_Operation_Serialization_Array_Size';
END

IF NOT EXISTS (SELECT * FROM sys.columns WHERE object_id = OBJECT_ID('Part_Operation_Serialization_Array_Size') AND name = 'Side')
BEGIN
    ALTER TABLE [dbo].[Part_Operation_Serialization_Array_Size]
    ADD [Side] NVARCHAR(10) NOT NULL CONSTRAINT DF_POSARRAY_SIZE_Side DEFAULT ('DEFAULT');

    PRINT 'Added Side to Part_Operation_Serialization_Array_Size';
END

-- Step 2: Add columns to Part_Operation_Serialization_Array_Index
IF NOT EXISTS (SELECT * FROM sys.columns WHERE object_id = OBJECT_ID('Part_Operation_Serialization_Array_Index') AND name = 'AreaID')
BEGIN
    ALTER TABLE [dbo].[Part_Operation_Serialization_Array_Index]
    ADD [AreaID] INT NOT NULL CONSTRAINT DF_POSARRAY_INDEX_AreaID DEFAULT (0);

    PRINT 'Added AreaID to Part_Operation_Serialization_Array_Index';
END

IF NOT EXISTS (SELECT * FROM sys.columns WHERE object_id = OBJECT_ID('Part_Operation_Serialization_Array_Index') AND name = 'Side')
BEGIN
    ALTER TABLE [dbo].[Part_Operation_Serialization_Array_Index]
    ADD [Side] NVARCHAR(10) NOT NULL CONSTRAINT DF_POSARRAY_INDEX_Side DEFAULT ('DEFAULT');

    PRINT 'Added Side to Part_Operation_Serialization_Array_Index';
