-- Step 3: Add columns to Part_Operation_Serialization_Array (base table)
IF NOT EXISTS (SELECT * FROM sys.columns WHERE object_id = OBJECT_ID('Part_Operation_Serialization_Array') AND name = 'AreaID')
BEGIN
    ALTER TABLE [dbo].[Part_Operation_Serialization_Array]
    ADD [AreaID] INT NOT NULL CONSTRAINT DF_POSARRAY_AreaID DEFAULT (0);

    PRINT 'Added AreaID to Part_Operation_Serialization_Array';
END

IF NOT EXISTS (SELECT * FROM sys.columns WHERE object_id = OBJECT_ID('Part_Operation_Serialization_Array') AND name = 'Side')
BEGIN
    ALTER TABLE [dbo].[Part_Operation_Serialization_Array]
    ADD [Side] NVARCHAR(10) NOT NULL CONSTRAINT DF_POSARRAY_Side DEFAULT ('DEFAULT');

    PRINT 'Added Side to Part_Operation_Serialization_Array';
END

-- Step 4: Create composite indexes for performance
IF NOT EXISTS (SELECT * FROM sys.indexes WHERE object_id = OBJECT_ID('Part_Operation_Serialization_Array_Size') AND name = 'IX_POSARRAY_SIZE_PartArea')
BEGIN
    CREATE NONCLUSTERED INDEX [IX_POSARRAY_SIZE_PartArea]
    ON [dbo].[Part_Operation_Serialization_Array_Size] ([PartID], [AreaID], [Side])
    INCLUDE ([Rows], [Cols]);

    PRINT 'Created index IX_POSARRAY_SIZE_PartArea';
END

IF NOT EXISTS (SELECT * FROM sys.indexes WHERE object_id = OBJECT_ID('Part_Operation_Serialization_Array_Index') AND name = 'IX_POSARRAY_INDEX_PartArea')
BEGIN
    CREATE NONCLUSTERED INDEX [IX_POSARRAY_INDEX_PartArea]
    ON [dbo].[Part_Operation_Serialization_Array_Index] ([PartID], [AreaID], [Side])
    INCLUDE ([MasterID], [PositionID], [ToIndex], [Row], [Col]);

    PRINT 'Created index IX_POSARRAY_INDEX_PartArea';
END

-- Step 5: Add composite unique constraint to prevent duplicate configurations
IF NOT EXISTS (SELECT * FROM sys.indexes WHERE object_id = OBJECT_ID('Part_Operation_Serialization_Array_Size') AND name = 'UQ_POSARRAY_SIZE_PartAreaSide')
BEGIN
    ALTER TABLE [dbo].[Part_Operation_Serialization_Array_Size]
    ADD CONSTRAINT [UQ_POSARRAY_SIZE_PartAreaSide] UNIQUE ([PartID], [AreaID], [Side], [Facility_Key]);

    PRINT 'Created unique constraint UQ_POSARRAY_SIZE_PartAreaSide';
END

-- Migration Complete
PRINT 'Migration completed successfully. All existing records now have AreaID=0 and Side=DEFAULT.';
GO
