/// <summary>
/// Helper method to query serialization array with area/side fallback logic.
/// Attempts: 1) Specific AreaID+Side, 2) AreaID+DEFAULT, 3) Global (0+DEFAULT)
/// </summary>
private string GetSerializationArrayQuery(int partId, int areaId, string side)
{
  return $@"
    WITH ConfigOptions AS (
      -- Option 1: Exact match (AreaID + Side)
      SELECT *, 1 AS Priority
      FROM [dbo].[Part_Operation_Serialization_Array_Size]
      WHERE PartID = {partId} AND AreaID = {areaId} AND Side = '{side}'

      UNION ALL

      -- Option 2: Area default (AreaID + DEFAULT)
      SELECT *, 2 AS Priority
      FROM [dbo].[Part_Operation_Serialization_Array_Size]
      WHERE PartID = {partId} AND AreaID = {areaId} AND Side = 'DEFAULT'

      UNION ALL

      -- Option 3: Global default (0 + DEFAULT)
      SELECT *, 3 AS Priority
      FROM [dbo].[Part_Operation_Serialization_Array_Size]
      WHERE PartID = {partId} AND AreaID = 0 AND Side = 'DEFAULT'
    )
    SELECT TOP 1 * FROM ConfigOptions
    ORDER BY Priority ASC";
}
```

### 3.2 Update GetActivateScannerArraySize Method

