[AcceptVerbs(HttpVerbs.Get | HttpVerbs.Post)]
[Authorize(Roles = "BF Administrator,BF Part Edit,BF Parameters Sheet Edit, BF Part Price Edit,BF Part Assembly Instructions Add")]
public JsonResult GetActivateScannerArraySize(int id, int areaId = 0, string side = "DEFAULT")
{
  try
  {
    SqlParameter[] parameters = new SqlParameter[]{
      new SqlParameter("@PartID", SqlDbType.Int){Value = id},
      new SqlParameter("@AreaID", SqlDbType.Int){Value = areaId},
      new SqlParameter("@Side", SqlDbType.NVarChar){Value = side}
    };

    // Use fallback query logic
    var result = db.Database.SqlQuery<Firstronic.Core.Entities.App.Engineering.tbl_Part_Operation_Serialization_Array_Size>(
      GetSerializationArrayQuery(id, areaId, side), parameters).FirstOrDefault();

    if (result != null)
    {
      return Json(new { 
        success = true,
        Rows = result.Rows ?? 0, 
        Cols = result.Cols ?? 0,
        AreaID = result.AreaID,
        Side = result.Side,
        ConfigType = result.AreaID == 0 && result.Side == "DEFAULT" ? "Global" : 
                     result.AreaID > 0 && result.Side == "DEFAULT" ? "Area Default" : 
                     "Area-Side Specific"
      }, JsonRequestBehavior.AllowGet);
    }

    return Json(new { success = true, Rows = 0, Cols = 0, ConfigType = "None" }, JsonRequestBehavior.AllowGet);
  }
  catch (Exception ex)
  {
    return Json(new { success = false, Rows = 0, Cols = 0, error = ex.Message }, JsonRequestBehavior.AllowGet);
  }
}
