[Authorize(Roles = "BF Administrator,BF Part Edit,BF Parameters Sheet Edit, BF Part Price Edit,BF Part Assembly Instructions Add")]
public JsonResult GetActivateScannerArrayData(int id, int areaId = 0, string side = "DEFAULT")
{
  try
  {
    SqlParameter[] idParameters = new SqlParameter[]{
      new SqlParameter("@Id", SqlDbType.Int){Value = id},
      new SqlParameter("@AreaID", SqlDbType.Int){Value = areaId},
      new SqlParameter("@Side", SqlDbType.NVarChar){Value = side}
    };

    // Query with fallback logic
    var data = db.Database.SqlQuery<Firstronic.Core.Entities.App.Engineering.tbl_Part_Operation_Serialization_Array_Index_FULL>(
      $@"WITH ConfigOptions AS (
           -- Option 1: Exact match
           SELECT *, 1 AS Priority
           FROM Part_Operation_Serialization_Array_Index
           WHERE PartID = @Id AND AreaID = @AreaID AND Side = @Side

           UNION ALL

           -- Option 2: Area default
           SELECT *, 2 AS Priority
           FROM Part_Operation_Serialization_Array_Index
           WHERE PartID = @Id AND AreaID = @AreaID AND Side = 'DEFAULT'

           UNION ALL

           -- Option 3: Global default
           SELECT *, 3 AS Priority
           FROM Part_Operation_Serialization_Array_Index
           WHERE PartID = @Id AND AreaID = 0 AND Side = 'DEFAULT'
         )
         SELECT TOP (1000)
           CO.AutoID,
           CS_idt_partnumbers.PartNumber,
           CO.MasterID,
           CO.PositionID,
           CO.ToIndex,
           CO.Row,
           CO.Col,
           CO.AreaID,
           CO.Side,
           ISNULL(PA.Area, 'Global Default') AS AreaName
         FROM (
           SELECT * FROM ConfigOptions WHERE Priority = (SELECT MIN(Priority) FROM ConfigOptions)
         ) CO
         INNER JOIN CS_idt_partnumbers ON CO.PartID = CS_idt_partnumbers.PartID
         LEFT JOIN PD_idt_areas PA ON CO.AreaID = PA.AreaID
         ORDER BY CO.ToIndex",
      idParameters).ToList();

    return Json(new { success = true, data = data }, JsonRequestBehavior.AllowGet);
  }
  catch (Exception ex)
  {
    return Json(new { success = false, error = ex.Message }, JsonRequestBehavior.AllowGet);
  }
}
