/// <summary>
/// Get list of all configurations for a part (default + area-specific)
/// </summary>
[AcceptVerbs(HttpVerbs.Get | HttpVerbs.Post)]
[Authorize(Roles = "BF Administrator,BF Part Edit")]
public JsonResult GetSerializationConfigurations(int partId)
{
  try
  {
    SqlParameter[] parameters = new SqlParameter[]{
      new SqlParameter("@PartID", SqlDbType.Int){Value = partId}
    };

    var configs = db.Database.SqlQuery<dynamic>($@"
      SELECT 
        SIZE.AutoID,
        SIZE.PartID,
        SIZE.AreaID,
        SIZE.Side,
        SIZE.Rows,
        SIZE.Cols,
        ISNULL(PA.Area, 'Global Default') AS AreaName,
        CASE 
          WHEN SIZE.AreaID = 0 AND SIZE.Side = 'DEFAULT' THEN 'Global Default'
          WHEN SIZE.AreaID > 0 AND SIZE.Side = 'DEFAULT' THEN 'Area Default'
          ELSE 'Area-Side Specific'
        END AS ConfigType,
        COUNT(IDX.AutoID) AS CellCount
      FROM Part_Operation_Serialization_Array_Size SIZE
      LEFT JOIN PD_idt_areas PA ON SIZE.AreaID = PA.AreaID
      LEFT JOIN Part_Operation_Serialization_Array_Index IDX 
        ON SIZE.PartID = IDX.PartID 
        AND SIZE.AreaID = IDX.AreaID 
        AND SIZE.Side = IDX.Side
      WHERE SIZE.PartID = @PartID
      GROUP BY SIZE.AutoID, SIZE.PartID, SIZE.AreaID, SIZE.Side, SIZE.Rows, SIZE.Cols, PA.Area
      ORDER BY SIZE.AreaID, SIZE.Side", parameters).ToList();

    return Json(new { success = true, data = configs }, JsonRequestBehavior.AllowGet);
  }
  catch (Exception ex)
  {
    return Json(new { success = false, error = ex.Message }, JsonRequestBehavior.AllowGet);
  }
}

/// <summary>
/// Copy configuration from source (AreaID/Side) to target (AreaID/Side)
/// </summary>
[AcceptVerbs(HttpVerbs.Post)]
[Authorize(Roles = "BF Administrator,BF Part Edit")]
public JsonResult CopySerializationConfiguration(int partId, int sourceAreaId, string sourceSide, int targetAreaId, string targetSide)
{
  try
  {
    SqlParameter[] parameters = new SqlParameter[]{
      new SqlParameter("@PartID", SqlDbType.Int){Value = partId},
      new SqlParameter("@SourceAreaID", SqlDbType.Int){Value = sourceAreaId},
      new SqlParameter("@SourceSide", SqlDbType.NVarChar){Value = sourceSide},
      new SqlParameter("@TargetAreaID", SqlDbType.Int){Value = targetAreaId},
      new SqlParameter("@TargetSide", SqlDbType.NVarChar){Value = targetSide}
    };

    // Copy size configuration
    db.Database.ExecuteSqlCommand($@"
      INSERT INTO Part_Operation_Serialization_Array_Size (PartID, Rows, Cols, AreaID, Side, Facility_Key, Part_Key)
      SELECT PartID, Rows, Cols, @TargetAreaID, @TargetSide, Facility_Key, Part_Key
      FROM Part_Operation_Serialization_Array_Size
      WHERE PartID = @PartID AND AreaID = @SourceAreaID AND Side = @SourceSide", parameters);

    // Copy index configuration
    db.Database.ExecuteSqlCommand($@"
      INSERT INTO Part_Operation_Serialization_Array_Index (PartID, MasterID, PositionID, ToIndex, Row, Col, AreaID, Side, Facility_Key, Part_Key)
      SELECT PartID, MasterID, PositionID, ToIndex, Row, Col, @TargetAreaID, @TargetSide, Facility_Key, Part_Key
      FROM Part_Operation_Serialization_Array_Index
      WHERE PartID = @PartID AND AreaID = @SourceAreaID AND Side = @SourceSide", parameters);

    // Copy base array record
    db.Database.ExecuteSqlCommand($@"
      INSERT INTO Part_Operation_Serialization_Array (PartID, AreaID, Side, Facility_Key, Part_Key)
      SELECT PartID, @TargetAreaID, @TargetSide, Facility_Key, Part_Key
      FROM Part_Operation_Serialization_Array
      WHERE PartID = @PartID AND AreaID = @SourceAreaID AND Side = @SourceSide", parameters);

    return Json(new { success = true, message = "Configuration copied successfully" });
  }
  catch (Exception ex)
  {
    return Json(new { success = false, error = ex.Message });
  }
}

/// <summary>
/// Delete specific configuration (does not allow deleting global default)
/// </summary>
[AcceptVerbs(HttpVerbs.Post)]
[Authorize(Roles = "BF Administrator,BF Part Edit")]
public JsonResult DeleteSerializationConfiguration(int partId, int areaId, string side)
{
  try
  {
    // Prevent deletion of global default
    if (areaId == 0 && side == "DEFAULT")
    {
      return Json(new { success = false, error = "Cannot delete global default configuration" });
    }

    SqlParameter[] parameters = new SqlParameter[]{
      new SqlParameter("@PartID", SqlDbType.Int){Value = partId},
      new SqlParameter("@AreaID", SqlDbType.Int){Value = areaId},
      new SqlParameter("@Side", SqlDbType.NVarChar){Value = side}
    };

    db.Database.ExecuteSqlCommand($@"
      DELETE FROM Part_Operation_Serialization_Array_Index 
      WHERE PartID = @PartID AND AreaID = @AreaID AND Side = @Side", parameters);

    db.Database.ExecuteSqlCommand($@"
      DELETE FROM Part_Operation_Serialization_Array_Size 
      WHERE PartID = @PartID AND AreaID = @AreaID AND Side = @Side", parameters);

    db.Database.ExecuteSqlCommand($@"
      DELETE FROM Part_Operation_Serialization_Array 
      WHERE PartID = @PartID AND AreaID = @AreaID AND Side = @Side", parameters);

    return Json(new { success = true, message = "Configuration deleted successfully" });
  }
  catch (Exception ex)
  {
    return Json(new { success = false, error = ex.Message });
  }
}
