// Configuration Management Variables
var currentAreaID = 0;
var currentSide = "DEFAULT";
var availableConfigurations = [];

// Load all configurations for the part on page load
function loadSerializationConfigurations() {
  var partId = $("#txtPartID").val();

  $.ajax({
    type: "POST",
    url: "/Engineering/PartNumber/GetSerializationConfigurations",
    data: JSON.stringify({ partId: partId }),
    contentType: "application/json; charset=utf-8",
    success: function (response) {
      if (response.success) {
        availableConfigurations = response.data;
        updateConfigurationDropdown();

        // Auto-load global default if exists
        if (availableConfigurations.length > 0) {
          $("#ddlSerializationConfig").val("0|DEFAULT").trigger('change');
        }
      }
    },
    error: function (xhr, status, error) {
      console.error("Failed to load configurations:", error);
    }
  });
}

// Update dropdown with available configurations
function updateConfigurationDropdown() {
  var dropdown = $("#ddlSerializationConfig");
  dropdown.empty();

  availableConfigurations.forEach(function (config) {
    var label = config.ConfigType + " - " + config.AreaName + 
                (config.Side !== "DEFAULT" ? " (Side " + config.Side + ")" : "") +
                " [" + config.CellCount + " cells]";
    var value = config.AreaID + "|" + config.Side;
    dropdown.append(new Option(label, value));
  });

  // Also populate copy-from dropdown
  var copyDropdown = $("#ddlCopyFromConfig");
  copyDropdown.find("option:not(:first)").remove();
  availableConfigurations.forEach(function (config) {
    var label = config.ConfigType + " - " + config.AreaName + 
                (config.Side !== "DEFAULT" ? " (Side " + config.Side + ")" : "");
    var value = config.AreaID + "|" + config.Side;
    copyDropdown.append(new Option(label, value));
  });
}

