using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Authorization;

namespace BeFirst.API.Controllers
{
    [Authorize]
    [ApiController]
    [Route("api/[controller]")]
    public class SerializationArrayController : ControllerBase
    {
        private readonly IDbConnection _dbConnection;

        public SerializationArrayController(IDbConnection dbConnection)
        {
            _dbConnection = dbConnection;
        }

        /// <summary>
        /// Get serialization order for a part with area/side fallback
        /// </summary>
        /// <param name="partId">Part ID</param>
        /// <param name="areaId">Manufacturing Area ID (optional, defaults to 0 for global)</param>
        /// <param name="side">Board Side (optional, defaults to DEFAULT)</param>
        [HttpGet("{partId}")]
        public async Task<IActionResult> GetSerializationOrder(
            int partId, 
            [FromQuery] int areaId = 0, 
            [FromQuery] string side = "DEFAULT")
        {
            var query = @"
                WITH ConfigOptions AS (
                    SELECT *, 1 AS Priority
                    FROM Part_Operation_Serialization_Array_Index
                    WHERE PartID = @PartID AND AreaID = @AreaID AND Side = @Side

                    UNION ALL

                    SELECT *, 2 AS Priority
                    FROM Part_Operation_Serialization_Array_Index
                    WHERE PartID = @PartID AND AreaID = @AreaID AND Side = 'DEFAULT'

                    UNION ALL

                    SELECT *, 3 AS Priority
                    FROM Part_Operation_Serialization_Array_Index
                    WHERE PartID = @PartID AND AreaID = 0 AND Side = 'DEFAULT'
                )
                SELECT AutoID, PartID, AreaID, Side, MasterID, PositionID, ToIndex, Row, Col
                FROM ConfigOptions
                WHERE Priority = (SELECT MIN(Priority) FROM ConfigOptions)
                ORDER BY ToIndex ASC";

            var result = await _dbConnection.QueryAsync<SerializationArrayIndexDto>(
                query, 
                new { PartID = partId, AreaID = areaId, Side = side });

            if (!result.Any())
            {
                return NotFound(new { message = "No serialization configuration found for this part" });
            }

            return Ok(new 
            { 
                partId = partId,
                areaId = result.First().AreaID,
                side = result.First().Side,
                configType = result.First().AreaID == 0 && result.First().Side == "DEFAULT" 
                    ? "Global" 
                    : result.First().AreaID > 0 && result.First().Side == "DEFAULT"
                        ? "AreaDefault"
                        : "AreaSideSpecific",
                serialization = result 
            });
        }
    }
}
```

